use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::env;
use std::ffi::OsStr;
use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::process::Command;

type GenResult<T> = Result<T, String>;

#[derive(Debug, Clone)]
struct Services {
    ids: BTreeSet<String>,
    docs: BTreeMap<String, String>,
}

#[derive(Debug, Clone)]
struct Need {
    alias: String,
    id: String,
    use_time: String,
    deny: Vec<String>,
    prefer: Vec<String>,
    avoid: Vec<String>,
    required: bool,
}

#[derive(Debug, Clone)]
struct Provide {
    alias: String,
    id: String,
    api: String,
    effect: Vec<String>,
    tag: Vec<Tag>,
}

#[derive(Debug, Clone)]
struct Tag {
    name: String,
    priority: i32,
}

#[derive(Debug, Clone)]
struct Module {
    name: String,
    title: String,
    enabled: bool,
    level: u8,
    stage: u16,
    level_dir: String,
    stage_dir: String,
    dir: PathBuf,
    needs: Vec<Need>,
    provides: Vec<Provide>,
}

#[derive(Debug, Clone)]
struct Provider {
    module: usize,
    provide: usize,
}

#[derive(Debug)]
struct Resolved {
    init_order: Vec<usize>,
    bindings: HashMap<(usize, usize), Option<Provider>>,
}

#[derive(Debug)]
enum Section {
    Root,
    Need(usize),
    Provide(usize),
}

fn main() {
    if let Err(err) = run() {
        eprintln!("error: {err}");
        std::process::exit(1);
    }
}

fn run() -> GenResult<()> {
    let mut args = env::args().skip(1);
    let Some(cmd) = args.next() else {
        return Err("usage: archgen <gen|gen-check|check-arch>".to_string());
    };

    let root = workspace_root()?;

    match cmd.as_str() {
        "gen" => generate(&root),
        "gen-check" => {
            generate(&root)?;
            if root.join(".git").exists() {
                let status = Command::new("git")
                    .args(["diff", "--exit-code", "--", "kernel/src", "docs/generated"])
                    .current_dir(&root)
                    .status()
                    .map_err(|err| format!("failed to run git diff: {err}"))?;
                if !status.success() {
                    return Err("generated files are out of date".to_string());
                }
            } else {
                eprintln!("gen-check: .git not found, skipped diff check");
            }
            Ok(())
        }
        "check-arch" => check_arch(&root),
        _ => Err(format!("unknown command `{cmd}`")),
    }
}

fn workspace_root() -> GenResult<PathBuf> {
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    if let Some(root) = manifest_dir.parent().and_then(Path::parent) {
        if root.join("kernel/src").exists() {
            return Ok(root.to_path_buf());
        }
    }

    let current = env::current_dir().map_err(|err| err.to_string())?;
    if current.join("kernel/src").exists() {
        return Ok(current);
    }
    Err("failed to locate workspace root with kernel/src".to_string())
}

fn generate(root: &Path) -> GenResult<()> {
    let modules = load_modules(root)?;
    let services = collect_services(&modules);
    validate_modules(&modules)?;
    let resolved = resolve_modules(&modules)?;

    generate_tree(root, &modules, &resolved)?;
    generate_init_plan(root, &modules, &resolved)?;
    generate_docs(root, &services, &modules, &resolved)?;

    Ok(())
}

fn collect_services(modules: &[Module]) -> Services {
    let mut ids = BTreeSet::new();

    for module in modules {
        for need in &module.needs {
            ids.insert(need.id.clone());
        }
        for provide in &module.provides {
            ids.insert(provide.id.clone());
        }
    }

    Services {
        ids,
        docs: BTreeMap::new(),
    }
}

fn load_modules(root: &Path) -> GenResult<Vec<Module>> {
    let kernel_src = root.join("kernel/src");
    let mut files = Vec::new();
    collect_module_tomls(&kernel_src, &mut files)
        .map_err(|err| format!("failed to scan {}: {err}", kernel_src.display()))?;
    files.sort();

    let mut modules = Vec::new();
    for path in files {
        modules.push(parse_module(root, &path)?);
    }

    modules.sort_by_key(|module| {
        (
            module.level,
            module.stage,
            module.stage_dir.clone(),
            module.name.clone(),
        )
    });

    Ok(modules)
}

fn collect_module_tomls(dir: &Path, out: &mut Vec<PathBuf>) -> io::Result<()> {
    if !dir.exists() {
        return Ok(());
    }
    for entry in fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            collect_module_tomls(&path, out)?;
        } else if path.file_name() == Some(OsStr::new("module.toml")) {
            out.push(path);
        }
    }
    Ok(())
}

fn parse_module(root: &Path, path: &Path) -> GenResult<Module> {

fn parse_module(root: &Path, path: &Path) -> GenResult<Module> {
    let text = fs::read_to_string(path)
        .map_err(|err| format!("failed to read {}: {err}", path.display()))?;

    let dir = path
        .parent()
        .ok_or_else(|| format!("module path has no parent: {}", path.display()))?
        .to_path_buf();
    let name_from_dir = dir
        .file_name()
        .and_then(OsStr::to_str)
        .ok_or_else(|| format!("bad module directory: {}", dir.display()))?
        .to_string();

    let rel = dir
        .strip_prefix(root.join("kernel/src"))
        .map_err(|_| format!("module is outside kernel/src: {}", dir.display()))?;
    let mut parts = rel
        .components()
        .filter_map(|part| part.as_os_str().to_str());
    let level_dir = parts
        .next()
        .ok_or_else(|| format!("module missing level directory: {}", dir.display()))?
        .to_string();
    let stage_dir = parts
        .next()
        .ok_or_else(|| format!("module missing stage directory: {}", dir.display()))?
        .to_string();

    let inferred_level = match level_dir.as_str() {
        "l0" => 0,
        "l1" => 1,
        "l2" => 2,
        _ => return Err(format!("unknown level directory `{level_dir}`")),
    };
    let inferred_stage = stage_dir
        .split('_')
        .next()
        .ok_or_else(|| format!("bad stage directory `{stage_dir}`"))?
        .parse::<u16>()
        .map_err(|_| format!("stage directory must start with a number: `{stage_dir}`"))?;

    let mut module = Module {
        name: name_from_dir,
        title: String::new(),
        enabled: true,
        level: inferred_level,
        stage: inferred_stage,
        level_dir,
        stage_dir,
        dir,
        needs: Vec::new(),
        provides: Vec::new(),
    };

    let mut section = Section::Root;
    for raw_line in text.lines() {
        let line = raw_line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        match line {
            "[[need]]" => {
                module.needs.push(Need {
                    alias: String::new(),
                    id: String::new(),
                    use_time: "run".to_string(),
                    deny: Vec::new(),
                    prefer: Vec::new(),
                    avoid: Vec::new(),
                    required: true,
                });
                section = Section::Need(module.needs.len() - 1);
                continue;
            }
            "[[provide]]" => {
                module.provides.push(Provide {
                    alias: String::new(),
                    id: String::new(),
                    api: "api".to_string(),
                    effect: Vec::new(),
                    tag: Vec::new(),
                });
                section = Section::Provide(module.provides.len() - 1);
                continue;
            }
            _ => {}
        }

        let Some((key, value)) = split_key_value(line) else {
            return Err(format!("bad line in {}: {line}", path.display()));
        };

        match section {
            Section::Root => match key {
                "name" => module.name = parse_string(value)?,
                "title" => module.title = parse_string(value)?,
                "enabled" => module.enabled = parse_bool(value)?,
                "level" => module.level = parse_u8(value)?,
                "stage" => module.stage = parse_u16(value)?,
                _ => {}
            },
            Section::Need(index) => {
                let need = module
                    .needs
                    .get_mut(index)
                    .ok_or_else(|| "internal need index error".to_string())?;
                match key {
                    "alias" => need.alias = parse_string(value)?,
                    "id" => need.id = parse_string(value)?,
                    "use" => need.use_time = parse_string(value)?,
                    "deny" => need.deny = parse_string_array(value)?,
                    "prefer" => need.prefer = parse_string_array(value)?,
                    "avoid" => need.avoid = parse_string_array(value)?,
                    "required" => need.required = parse_bool(value)?,
                    _ => {}
                }
            }
            Section::Provide(index) => {
                let provide = module
                    .provides
                    .get_mut(index)
                    .ok_or_else(|| "internal provide index error".to_string())?;
                match key {
                    "alias" => provide.alias = parse_string(value)?,
                    "id" => provide.id = parse_string(value)?,
                    "api" => provide.api = parse_string(value)?,
                    "effect" => provide.effect = parse_string_array(value)?,
                    "tag" => provide.tag = parse_tag_array(value)?,
                    _ => {}
                }
            }
        }
    }

    if module.title.is_empty() {
        module.title = module.name.replace('_', " ");
    }
    for need in &mut module.needs {
        if need.alias.is_empty() {
            need.alias = need.id.to_ascii_lowercase();
        }
    }
    for provide in &mut module.provides {
        if provide.alias.is_empty() {
            provide.alias = provide.id.to_ascii_lowercase();
        }
    }

    Ok(module)
}

fn validate_modules(modules: &[Module]) -> GenResult<()> {
    let mut errors = Vec::new();

    for module in modules {
        if module.name.trim().is_empty() {
            errors.push(format!("{} has empty name", module.dir.display()));
        }
        if !is_rust_ident(&module.name) {
            errors.push(format!(
                "{} uses non-rust module name `{}`",
                module.dir.display(),
                module.name
            ));
        }
        if module.level > 2 {
            errors.push(format!(
                "{} has invalid level {}",
                module.name, module.level
            ));
        }
        if module.level != level_number(&module.level_dir).unwrap_or(module.level) {
            errors.push(format!(
                "{} level field does not match directory {}",
                module.name, module.level_dir
            ));
        }
        if module.stage != stage_number(&module.stage_dir).unwrap_or(module.stage) {
            errors.push(format!(
                "{} stage field does not match directory {}",
                module.name, module.stage_dir
            ));
        }
        let mut need_aliases = BTreeSet::new();
        for need in &module.needs {
            if !is_arch_id(&need.id) {
                errors.push(format!("{} needs invalid id `{}`", module.name, need.id));
            }
            if !need_aliases.insert(need.alias.clone()) {
                errors.push(format!(
                    "{} has duplicate need alias `{}`",
                    module.name, need.alias
                ));
            }
            for effect in &need.deny {
                if !is_arch_id(effect) {
                    errors.push(format!(
                        "{} need `{}` denies invalid effect `{}`",
                        module.name, need.alias, effect
                    ));

                    ));
                }
            }
            for tag in need.prefer.iter().chain(need.avoid.iter()) {
                if !is_tag_name(tag) {
                    errors.push(format!(
                        "{} need `{}` uses invalid tag `{}`",
                        module.name, need.alias, tag
                    ));
                }
            }
        }
        for provide in &module.provides {
            if !is_arch_id(&provide.id) {
                errors.push(format!(
                    "{} provides invalid id `{}`",
                    module.name, provide.id
                ));
            }
            for effect in &provide.effect {
                if !is_arch_id(effect) {
                    errors.push(format!(
                        "{} provide `{}` has invalid effect `{}`",
                        module.name, provide.alias, effect
                    ));
                }
            }
            for tag in &provide.tag {
                if !is_tag_name(&tag.name) {
                    errors.push(format!(
                        "{} provide `{}` has invalid tag `{}`",
                        module.name, provide.alias, tag.name
                    ));
                }
            }
        }
    }

    if errors.is_empty() {
        Ok(())
    } else {
        Err(errors.join("\n"))
    }
}

fn resolve_modules(modules: &[Module]) -> GenResult<Resolved> {
    let enabled: Vec<usize> = modules
        .iter()
        .enumerate()
        .filter_map(|(index, module)| module.enabled.then_some(index))
        .collect();

    let mut stages = BTreeSet::new();
    for &index in &enabled {
        let module = &modules[index];
        stages.insert((module.level, module.stage));
    }

    let mut book: Vec<Provider> = Vec::new();
    let mut done: HashSet<usize> = HashSet::new();
    let mut init_order = Vec::new();
    let mut bindings: HashMap<(usize, usize), Option<Provider>> = HashMap::new();

    for (level, stage) in stages {
        let stage_modules: Vec<usize> = enabled
            .iter()
            .copied()
            .filter(|&index| {
                let module = &modules[index];
                module.level == level && module.stage == stage
            })
            .collect();

        loop {
            let mut progress = false;

            for &module_index in &stage_modules {
                if done.contains(&module_index) {
                    continue;
                }

                match try_bind_module(modules, module_index, &book) {
                    BindAttempt::Ready(bound) => {
                        for (need_index, provider) in bound {
                            bindings.insert((module_index, need_index), provider);
                        }
                        for provide_index in 0..modules[module_index].provides.len() {
                            book.push(Provider {
                                module: module_index,
                                provide: provide_index,
                            });
                        }
                        done.insert(module_index);
                        init_order.push(module_index);
                        progress = true;
                    }
                    BindAttempt::Blocked => {}
                }
            }

            if stage_modules.iter().all(|index| done.contains(index)) {
                break;
            }
            if !progress {
                return Err(format_blocked_stage(
                    modules,
                    level,
                    stage,
                    &stage_modules,
                    &book,
                ));
            }
        }
    }

    Ok(Resolved {
        init_order,
        bindings,
    })
}

enum BindAttempt {
    Ready(Vec<(usize, Option<Provider>)>),
    Blocked,
}

fn try_bind_module(modules: &[Module], module_index: usize, book: &[Provider]) -> BindAttempt {
    let module = &modules[module_index];
    let mut bound = Vec::new();

    for (need_index, need) in module.needs.iter().enumerate() {
        let provider = find_provider(modules, need, book);
        if provider.is_none() && need.required {
            return BindAttempt::Blocked;
        }
        bound.push((need_index, provider));
    }

    BindAttempt::Ready(bound)
}

fn find_provider(modules: &[Module], need: &Need, book: &[Provider]) -> Option<Provider> {
    let mut best: Option<(i32, usize, Provider)> = None;
    for (order, provider) in book.iter().enumerate() {
        let provided = &modules[provider.module].provides[provider.provide];
        if provided.id != need.id {
            continue;
        }
        if provided
            .effect
            .iter()
            .any(|effect| need.deny.iter().any(|deny| deny == effect))
        {
            continue;
        }
        let score = provider_score(provided, need);
        let candidate = (score, order, provider.clone());
        let replace = match best.as_ref() {
            Some((best_score, best_order, _)) => {
                score > *best_score || score == *best_score && order > *best_order
            }
            None => true,
        };
        if replace {
            best = Some(candidate);
        }
    }
    best.map(|(_, _, provider)| provider)
}

fn provider_score(provide: &Provide, need: &Need) -> i32 {
    provide
        .tag
        .iter()
        .map(|tag| {
            let mut score = tag.priority;
            if need.prefer.iter().any(|prefer| prefer == &tag.name) {
                score += 99;
            }
            if need.avoid.iter().any(|avoid| avoid == &tag.name) {
                score -= 99;
            }
            score
        })
        .sum()
}

fn format_blocked_stage(
    modules: &[Module],
    level: u8,
    stage: u16,
    stage_modules: &[usize],
    book: &[Provider],
) -> String {
