use core::sync::atomic::{AtomicBool, Ordering};

use super::api::{Page, PageAllocError};
use super::need;

const MAX_FREE_RANGES: usize = 64;

#[derive(Clone, Copy)]
struct PageRange {
    start: usize,
    end: usize,
}

impl PageRange {
    const fn empty() -> Self {
        Self { start: 0, end: 0 }
    }

    fn pages(self) -> usize {
        self.end.saturating_sub(self.start) / crate::arch::vm::PAGE_SIZE
    }
}

static LOCKED: AtomicBool = AtomicBool::new(false);
static mut FREE_RANGES: [PageRange; MAX_FREE_RANGES] = [PageRange::empty(); MAX_FREE_RANGES];
static mut FREE_RANGE_COUNT: usize = 0;
static mut MANAGED_RANGES: [PageRange; MAX_FREE_RANGES] = [PageRange::empty(); MAX_FREE_RANGES];
static mut MANAGED_RANGE_COUNT: usize = 0;

pub fn init() -> crate::init::InitResult {
    with_lock(|| unsafe {
        FREE_RANGE_COUNT = 0;
        MANAGED_RANGE_COUNT = 0;
        for region in need::memory_map::usable_regions() {
            let start = align_up(region.start, crate::arch::vm::PAGE_SIZE);
            let end = align_down(region.end());
            if end > start {
                let range = PageRange { start, end };
                push_managed_range(range).map_err(|_| crate::init::InitError::Failed)?;
                push_free_range(range).map_err(|_| crate::init::InitError::Failed)?;
            }
        }
        sort_ranges();
        Ok(())
    })
}

pub fn alloc_page() -> Result<Page, PageAllocError> {
    with_lock(|| unsafe {
        for index in 0..FREE_RANGE_COUNT {
            let range = FREE_RANGES[index];
            if range.start < range.end {
                let paddr = range.start;
                FREE_RANGES[index].start = range.start + crate::arch::vm::PAGE_SIZE;
                if FREE_RANGES[index].start == FREE_RANGES[index].end {
                    remove_range(index);
                }
                return Ok(Page { paddr });
            }
        }
        Err(PageAllocError::OutOfMemory)
    })
}

pub fn dealloc_page(paddr: usize) -> Result<(), PageAllocError> {
    if paddr % crate::arch::vm::PAGE_SIZE != 0 {
        return Err(PageAllocError::BadAddress);
    }

    with_lock(|| unsafe {
        if !is_managed(paddr) {
            return Err(PageAllocError::BadAddress);
        }
        if is_free(paddr) {
            return Err(PageAllocError::AlreadyFree);
        }

        push_free_range(PageRange {
            start: paddr,
            end: paddr + crate::arch::vm::PAGE_SIZE,
        })?;
        sort_ranges();
        coalesce_ranges();
        Ok(())
    })
}

pub fn free_pages() -> usize {
    with_lock(|| unsafe {
        let mut total = 0;
        for index in 0..FREE_RANGE_COUNT {
            total += FREE_RANGES[index].pages();
        }
        total
    })
}

// 页分配器内部锁：IRQ 安全自旋锁，附带重入检测。
// 重入检测使用 LOG_EARLY 无条件输出——page_alloc 位于 Stage 30，
// 早于 dynamic_log（Stage 40），log::info! 此时为无操作，且重入场景下
// 日志系统本身亦不可信赖。
fn with_lock<R>(f: impl FnOnce() -> R) -> R {
    let flags = need::raw_lock::irq_save();
    if LOCKED.load(Ordering::Relaxed) {
        need::log_early::record(format_args!(
            "[page] BUG: with_lock reentry detected\n"
        ));
    }
    while LOCKED
        .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
        .is_err()
    {
        need::raw_lock::raw_lock_relax();
    }
    let result = f();
    LOCKED.store(false, Ordering::Release);
    need::raw_lock::irq_restore(flags);
    result
}

unsafe fn push_free_range(range: PageRange) -> Result<(), PageAllocError> {
    if range.end <= range.start {
        return Ok(());
    }
    if FREE_RANGE_COUNT < MAX_FREE_RANGES {
        FREE_RANGES[FREE_RANGE_COUNT] = range;
        FREE_RANGE_COUNT += 1;
        Ok(())
    } else {
        Err(PageAllocError::OutOfMemory)
    }
}

unsafe fn push_managed_range(range: PageRange) -> Result<(), PageAllocError> {
    if range.end <= range.start {
        return Ok(());
    }
    if MANAGED_RANGE_COUNT < MAX_FREE_RANGES {
        MANAGED_RANGES[MANAGED_RANGE_COUNT] = range;
        MANAGED_RANGE_COUNT += 1;
        Ok(())
    } else {
        Err(PageAllocError::OutOfMemory)
    }
}

unsafe fn remove_range(index: usize) {
    for i in index + 1..FREE_RANGE_COUNT {
        FREE_RANGES[i - 1] = FREE_RANGES[i];
    }

