pub type ThreadContext = need::thread_context::KernelContext;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TaskId(pub usize);

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SchedulerError {
    InvalidTask,
    NotFound,
    AlreadyRegistered,
    InvalidState,
}

pub type SchedulerResult<T> = Result<T, SchedulerError>;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Ready,
    Running,
    Blocked { deadline_ns: Option<u64> },
    Exited,
}

struct Entry {
    id: TaskId,
    state: State,
    context: ThreadContext,
}

struct Scheduler {
    tasks: Vec<Entry>,
}

impl Scheduler {
    const fn new() -> Self {
        Self { tasks: Vec::new() }
    }

    fn find(&mut self, id: TaskId) -> SchedulerResult<&mut Entry> {
        self.tasks
            .iter_mut()
            .find(|task| task.id == id)
            .ok_or(SchedulerError::NotFound)
    }

    fn register(&mut self, id: TaskId, context: ThreadContext) -> SchedulerResult<()> {
        if id.0 == 0 {
            return Err(SchedulerError::InvalidTask);
        }
        if self.tasks.iter().any(|task| task.id == id) {
            return Err(SchedulerError::AlreadyRegistered);
        }
        self.tasks.push(Entry {
            id,
            state: State::Ready,
            context,
        });
        Ok(())
    }
}

struct SchedulerCell {
    locked: AtomicBool,
    value: UnsafeCell<Scheduler>,
}

unsafe impl Sync for SchedulerCell {}

impl SchedulerCell {
    const fn new(value: Scheduler) -> Self {
        Self {
            locked: AtomicBool::new(false),
            value: UnsafeCell::new(value),
        }
    }

    fn with<R>(&self, f: impl FnOnce(&mut Scheduler) -> R) -> R {
        let _irq_off = need::irq::IrqOff::new();
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
        let result = f(unsafe { &mut *self.value.get() });
        self.locked.store(false, Ordering::Release);
        result
    }
}

/// 在调度器中为该 ID 建立任务条目，初始状态为 Ready。重复注册会返回错误。
pub fn register_task(id: TaskId, context: ThreadContext) -> SchedulerResult<()> {
    SCHEDULER.with(|scheduler| scheduler.register(id, context))
}

/// 将指定任务标记为 Running 状态，同时更新当前任务指针。非 Running 任务的 CPU 不会再执行它。
pub fn set_current(id: TaskId) -> SchedulerResult<()> {
    //原子地(以最强顺序) 存入id：当前正在运行的任务ID
    SCHEDULER.with(|scheduler| {
        let target_index = scheduler
            .tasks
            .iter()
            .position(|task| task.id == id)
            .ok_or(SchedulerError::NotFound)?;
        if matches!(scheduler.tasks[target_index].state, State::Exited) {
            return Err(SchedulerError::InvalidState);
        }

        let current = CURRENT.load(Ordering::SeqCst);
        if current != 0 && current != id.0 {
            if let Some(old) = scheduler
                .tasks
                .iter_mut()
                .find(|task| task.id == TaskId(current))
            {
                if matches!(old.state, State::Running) {
                    old.state = State::Ready;
                }
            }
        }
        //标记为running
        scheduler.tasks[target_index].state = State::Running;
        CURRENT.store(id.0, Ordering::SeqCst);
        Ok(())
    })
}

