impl OpenFlags {
    /// 只读。
    pub const RDONLY: Self = Self(0);
    /// 只写。
    pub const WRONLY: Self = Self(1);
    /// 读写。
    pub const RDWR: Self = Self(2);
    /// 若文件不存在则创建。
    pub const CREATE: Self = Self(0x40);
    /// 打开时截断（清空）文件内容。
    pub const TRUNC: Self = Self(0x200);
    /// 写入追加到文件末尾。
    pub const APPEND: Self = Self(0x400);
    /// 要求打开的目标必须是目录。
    pub const DIRECTORY: Self = Self(0x1_0000);

    /// 将原始 `u32` 位掩码转为 `OpenFlags`。
    pub const fn from_bits(bits: u32) -> Self {
        Self(bits)
    }

    /// 返回 `OpenFlags` 对应的原始 `u32` 位掩码。
    pub const fn bits(self) -> u32 {
        self.0
    }

    /// 判断是否包含 `other` 所表示的全部标志位。
    pub const fn contains(self, other: Self) -> bool {
        self.0 & other.0 == other.0
    }

    fn access(self) -> u32 {
        self.0 & 0b11
    }

    fn can_read(self) -> bool {
        self.access() != Self::WRONLY.0
    }

    fn can_write(self) -> bool {
        matches!(self.access(), 1 | 2)
    }

    fn create(self) -> bool {
        self.contains(Self::CREATE)
    }

    fn truncate(self) -> bool {
        self.contains(Self::TRUNC)
    }

    fn append(self) -> bool {
        self.contains(Self::APPEND)
    }

    fn directory(self) -> bool {
        self.contains(Self::DIRECTORY)
    }
}

impl core::ops::BitOr for OpenFlags {
    type Output = Self;

    fn bitor(self, rhs: Self) -> Self::Output {
        Self(self.0 | rhs.0)
    }
