/// 进程克隆：以当前任务为模板创建子任务，子任务与父任务共享入口点和代码段；根据 CloneArgs 可让子任务共享或独立复制地址空间、共享线程组，并支持在父子地址空间中写入 TID 供用户态同步使用。
pub mod fork {
    use alloc::string::ToString;

    use super::super::need::*;

    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    /// 克隆参数：share_address_space 决定子任务复用父地址空间还是深拷贝；share_thread_group 将子任务加入同一线程组；user_stack/tls 覆盖默认栈和 TLS 位置；parent_tid/child_tid 指定写入新 TID 的用户地址（0 表示不写入）。
    pub struct CloneArgs {
        pub child_frame: task::TrapFrame,
        pub user_stack: Option<usize>,
        pub tls: Option<usize>,
        pub share_address_space: bool,
        pub share_thread_group: bool,
        pub parent_tid: Option<usize>,
        pub child_tid: Option<usize>,
    }

    /// 以当前任务为模板按 CloneArgs 创建子任务：共享或复制地址空间，选择性加入线程组；分配独立内核栈并初始化线程上下文；在 parent_tid 和 child_tid 地址处分别写入子任务 ID 供用户态线程同步。
    pub fn clone_current(args: CloneArgs) -> Result<task::TaskId, sys_error::SysError> {
        let parent = task::current().ok_or(sys_error::SysError::NoSys)?;
        let info = task::info(parent).map_err(map_task)?;
        let parent_space = info.address_space.ok_or(sys_error::SysError::Fault)?;
        let child_space = if args.share_address_space {
            parent_space
        } else {
            user_memory::clone_address_space(parent_space)
                .map_err(|_| sys_error::SysError::Fault)?
        };
        let user_stack = args.user_stack.unwrap_or(info.user_stack);
        let tls = args.tls.unwrap_or(info.tls);

        let child = task::spawn_fork(task::SpawnFork {
            exec_path: info.exec_path.to_string(),
            cwd: info.cwd.to_string(),
            entry: info.entry,
            user_stack,
            tls,
            address_space: child_space,
            child_frame: args.child_frame,
        })
        .map_err(map_task)?;

        if args.share_thread_group {
            let group = task::thread_group(parent).map_err(map_task)?;
            task::set_thread_group(child, group).map_err(map_task)?;
        }

        write_tid(parent_space, args.parent_tid, child.0)?;
        write_tid(child_space, args.child_tid, child.0)?;
        Ok(child)
    }

    fn write_tid(
        space: user_memory::AddressSpace,
        ptr: Option<usize>,
        value: usize,
    ) -> Result<(), sys_error::SysError> {
        let Some(ptr) = ptr.filter(|ptr| *ptr != 0) else {
            return Ok(());
        };
        let raw = (value as u32).to_ne_bytes();
        user_memory::write(space, ptr, &raw).map_err(|_| sys_error::SysError::Fault)
    }

    fn map_task(error: task::TaskError) -> sys_error::SysError {
        match error {
            task::TaskError::NoMemory => sys_error::SysError::TooManyOpenFiles,
            task::TaskError::BadAddress | task::TaskError::Memory(_) => sys_error::SysError::Fault,
            task::TaskError::NotFound | task::TaskError::InvalidState => sys_error::SysError::NoSys,
        }
    }
}

