    static EXITED_CHILDREN: ExitedChildren = ExitedChildren::new();

    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    struct ChildExit {
        pid: usize,
        status: usize,
    }

    struct ExitedChildren {
        locked: AtomicBool,
        queue: UnsafeCell<Option<Vec<ChildExit>>>,
    }

    unsafe impl Sync for ExitedChildren {}

    impl ExitedChildren {
        const fn new() -> Self {
            Self {
                locked: AtomicBool::new(false),
                queue: UnsafeCell::new(None),
            }
        }

        fn with<R>(&self, f: impl FnOnce(&mut Vec<ChildExit>) -> R) -> R {
            while self
                .locked
                .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
                .is_err()
            {
                core::hint::spin_loop();
            }
            let result = unsafe {
                let queue = &mut *self.queue.get();
                if queue.is_none() {
                    *queue = Some(Vec::new());
                }
                f(queue.as_mut().unwrap())
            };
            self.locked.store(false, Ordering::Release);
            result
        }

        fn push(&self, child: ChildExit) {
            self.with(|queue| queue.push(child));
        }

        fn take_matching(&self, pid: usize) -> Option<ChildExit> {
            self.with(|queue| {
                let index = if pid == 0 || pid == usize::MAX {
                    (!queue.is_empty()).then_some(0)
                } else {
                    queue.iter().position(|child| child.pid == pid)
                }?;
                Some(queue.remove(index))
            })
        }
    }

