#[derive(Debug, Clone)]
struct LruEntry<V> {
    value: V,
    last_access: u64,
}

#[derive(Debug, Clone)]
struct LruCache<K: Ord + Clone, V> {
    entries: BTreeMap<K, LruEntry<V>>,
    capacity: usize,
    evict_batch: usize,
    clock: u64,
}

impl<K: Ord + Clone, V> LruCache<K, V> {
    const fn new(capacity: usize, evict_batch: usize) -> Self {
        Self {
            entries: BTreeMap::new(),
            capacity,
            evict_batch,
            clock: 0,
        }
    }

    fn get_cloned(&mut self, key: &K) -> Option<V>
    where
        V: Clone,
    {
        let next_ts = self.next_timestamp();
        if let Some(entry) = self.entries.get_mut(key) {
            entry.last_access = next_ts;
            Some(entry.value.clone())
        } else {
            None
        }
    }

    fn get_map<R>(&mut self, key: &K, f: impl FnOnce(&V) -> R) -> Option<R> {
        let next_ts = self.next_timestamp();
        if let Some(entry) = self.entries.get_mut(key) {
            entry.last_access = next_ts;
            Some(f(&entry.value))
        } else {
            None
        }
    }

    fn insert(&mut self, key: K, value: V) {
        let next_ts = self.next_timestamp();
        if self.entries.len() >= self.capacity && !self.entries.contains_key(&key) {
            self.evict_oldest();
        }
        self.entries.insert(
            key,
            LruEntry {
                value,
                last_access: next_ts,
            },
        );
    }

    fn remove(&mut self, key: &K) {
        self.entries.remove(key);
    }

    fn clear(&mut self) {
        self.entries.clear();
    }

    fn next_timestamp(&mut self) -> u64 {
        self.clock = self.clock.wrapping_add(1);
        self.clock
    }

    fn evict_oldest(&mut self) {
        let count = self.evict_batch.max(1).min(self.capacity.max(1));
        let mut by_ts = self
            .entries
            .iter()
            .map(|(key, entry)| (key.clone(), entry.last_access))
            .collect::<Vec<_>>();
        if count < by_ts.len() {
            by_ts.select_nth_unstable_by_key(count - 1, |&(_, ts)| ts);
        }
        for (key, _) in by_ts.into_iter().take(count) {
            self.entries.remove(&key);
        }
    }
}

