pub mod mount {
    use core::sync::atomic::Ordering;

    use super::{ext4, normalize_path, ExtraMount, EXTRA_EXT4_MOUNT, ROOT_KIND};

    /// 根文件系统类型。
    #[repr(usize)]
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub enum RootKind {
        None = 0,
        Ext4 = 1,
    }

    impl RootKind {
        fn from_raw(value: usize) -> Self {
            match value {
                1 => Self::Ext4,
                _ => Self::None,
            }
        }
    }

    /// 尝试将默认块设备挂载为 ext4 根文件系统。
    pub fn try_mount_default_ext4_root() {
        let _ = ext4::mount_first_root().map(|()| {
            ROOT_KIND.store(RootKind::Ext4 as usize, Ordering::Release);
            super::clear_vfs_caches();
        });
    }

    /// 将指定块设备挂载为 ext4 根文件系统。
    pub fn mount_ext4_root(device_index: usize) -> Result<(), MountError> {
        ext4::mount_root(device_index).map_err(MountError::from)?;
        ROOT_KIND.store(RootKind::Ext4 as usize, Ordering::Release);
        super::clear_vfs_caches();
        log::info!("vfs: mounted ext4 root from device {}", device_index);
        Ok(())
    }

    /// 将额外块设备挂载到指定目录（如 `/home`），目前仅支持 ext4。
    pub fn mount_extra_ext4(device_index: usize, mount_point: &str) -> Result<(), MountError> {
        let mount_point = normalize_path(mount_point).map_err(|_| MountError::Device)?;
        ext4::mount_root_at(super::EXTRA_EXT4.0, device_index).map_err(MountError::from)?;
        EXTRA_EXT4_MOUNT.with(|slot| {
            *slot = Some(ExtraMount {
                path: mount_point.clone(),
            });
        });
        super::clear_vfs_caches();
        log::info!(
            "vfs: mounted extra ext4 device {} at {}",
            device_index,
            mount_point
        );
        Ok(())
    }

    /// 返回当前根文件系统的类型。
    pub fn root_kind() -> RootKind {
        RootKind::from_raw(ROOT_KIND.load(Ordering::Acquire))
    }

    /// 默认根文件系统是否已挂载。
    pub fn is_root_mounted() -> bool {
        matches!(root_kind(), RootKind::Ext4) && ext4::is_root_mounted()
    }

    /// 额外 ext4 设备是否已挂载。
    pub fn is_extra_mounted() -> bool {
        EXTRA_EXT4_MOUNT.with(|slot| slot.is_some())
            && ext4::is_root_mounted_at(super::EXTRA_EXT4.0)
    }

    /// 描述 Ext4 根文件系统挂载阶段可能出现的错误。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub enum MountError {
        Disabled,
        Device,
        Format,
    }

