    use super::super::need;

    /// CharDeviceId 结构体，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct CharDeviceId(usize);

    impl CharDeviceId {
        /// 提供 `index` 对应的能力接口。
        ///
        /// 参数：
        /// - `self`：当前实例。
        ///
        /// 返回：`usize`。
        pub fn index(self) -> usize {
            self.0
        }
    }

    /// CharError 枚举，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub enum CharError {
        InvalidDevice,
        Io,
    }

    /// 字符设备驱动抽象：由具体驱动实现，注册后通过 CharDeviceId 供上层按字节读写。
    pub trait CharDevice: Send {
        /// 返回设备名称，用于调试输出和设备枚举。
        fn name(&self) -> &str;
        /// 从设备读取字节到 buf，返回实际读取的字节数。
        fn read(&mut self, buf: &mut [u8]) -> Result<usize, CharError>;
        /// 将 buf 中的字节写入设备，返回实际写入的字节数。
        fn write(&mut self, buf: &[u8]) -> Result<usize, CharError>;
    }

    /// 注册一个实现对象并返回后续访问使用的标识。
    ///
    /// 参数：
    /// - `device`：要注册的设备实现对象。
    ///
    /// 返回：成功时返回 `CharDeviceId`；失败时返回 `CharError`。
    pub fn register(device: Box<dyn CharDevice>) -> Result<CharDeviceId, CharError> {
        REGISTRY.with(|devices| {
            let id = CharDeviceId(devices.len());
            devices.push(device);
            Ok(id)
        })
    }

    /// 返回当前已注册或已存在的对象数量。
    ///
    /// 返回：`usize`。
    pub fn count() -> usize {
        REGISTRY.with(|devices| devices.len())
    }

    /// 按索引查询对象标识。
    ///
    /// 参数：
    /// - `index`：要查询的下标。
    ///
    /// 返回：`Option<CharDeviceId>`。
    pub fn by_index(index: usize) -> Option<CharDeviceId> {
        REGISTRY.with(|devices| (index < devices.len()).then_some(CharDeviceId(index)))
    }

    /// 读取数据到调用者提供的缓冲区。
    ///
    /// 参数：
    /// - `id`：对象标识，由对应注册或打开接口返回。
    /// - `buf`：调用者提供的缓冲区；读取时写入该缓冲区。
    ///
    /// 返回：成功时返回 `usize`；失败时返回 `CharError`。
    pub fn read(id: CharDeviceId, buf: &mut [u8]) -> Result<usize, CharError> {
        REGISTRY
            .with(|devices| devices.get_mut(id.0).map(|device| device.read(buf)))
            .ok_or(CharError::InvalidDevice)?
    }

    /// 写出调用者提供的数据。
    ///
    /// 参数：
    /// - `id`：对象标识，由对应注册或打开接口返回。
    /// - `buf`：调用者提供的缓冲区；读取时写入该缓冲区。
    ///
    /// 返回：成功时返回 `usize`；失败时返回 `CharError`。
    pub fn write(id: CharDeviceId, buf: &[u8]) -> Result<usize, CharError> {
        REGISTRY
            .with(|devices| devices.get_mut(id.0).map(|device| device.write(buf)))
            .ok_or(CharError::InvalidDevice)?
    }

    static REGISTRY: need::lock::Mutex<Vec<Box<dyn CharDevice>>> =
        need::lock::Mutex::new(Vec::new());
}
