            unmap_page(table, va)?;
        }
        Ok(())

    impl From<ext4::MountError> for MountError {
        fn from(value: ext4::MountError) -> Self {
            match value {
                ext4::MountError::Disabled => Self::Disabled,
                ext4::MountError::Device => Self::Device,
                ext4::MountError::Format => Self::Format,
            }
        }
    }

    /// 标记 tmpfs 为就绪状态。
    pub fn set_tmpfs_ready() {
        super::tmpfs::init();
    }

    /// tmpfs 是否已启用。
    pub fn tmpfs_ready() -> bool {
        super::tmpfs::ready()
    }
