pub mod path {
    use super::{
        cached_metadata_for_path, insert_symlink, lookup_path, mount, remove_symlink,
        resolve_ext4_path, Metadata, NodeKind, SysError,
    };

    /// 路径查询结果，包含节点类型。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct Lookup {
        pub kind: NodeKind,
    }

    /// 查询路径是否存在并返回其节点类型。
    pub fn lookup(path: &str) -> Result<Lookup, SysError> {
        lookup_path(path, false).map(|cached| Lookup { kind: cached.kind })
    }

    /// 判断路径是否存在。
    pub fn exists(path: &str) -> bool {
        lookup(path).is_ok()
    }

    /// 判断路径是否为绝对路径（以 `/` 开头）。
    pub fn is_absolute(path: &str) -> bool {
        path.starts_with('/')
    }

    /// 读取路径的元数据，若为符号链接则跟随。
    pub fn metadata(path: &str) -> Result<Metadata, SysError> {
        cached_metadata_for_path(path, true)
    }

    /// 获取路径元数据，若为符号链接则不跟随（返回符号链接自身的属性）。
    pub fn symlink_metadata(path: &str) -> Result<Metadata, SysError> {
        cached_metadata_for_path(path, false)
    }

    /// 创建目录。
    pub fn mkdir(path: &str) -> Result<(), SysError> {
        let resolved = resolve_ext4_path(path)?;
        let result = super::ext4::mkdir_at(resolved.mount.0, &resolved.inner)
            .map(|_| ())
            .map_err(super::map_ext4);
        if result.is_ok() {
            super::invalidate_after_path_change(&resolved.display);
        }
        result
    }

    /// 创建符号链接，`target` 为目标路径，`link_path` 为链接文件路径。
    pub fn symlink(target: &str, link_path: &str) -> Result<(), SysError> {
        let link_path = super::normalize_path(link_path)?;
        insert_symlink(link_path, target)
    }

    /// 重命名文件或目录，可搭配 `flags` 控制覆盖行为（如 `RENAME_NOREPLACE`）。
    pub fn rename(old_path: &str, new_path: &str, flags: u32) -> Result<(), SysError> {
        let old_path = super::normalize_path(old_path)?;
        let new_path = super::normalize_path(new_path)?;
        let old_resolved = resolve_ext4_path(&old_path)?;
        let new_resolved = resolve_ext4_path(&new_path)?;
        if old_resolved.mount != new_resolved.mount {
            return Err(SysError::OperationNotSupported);
        }

        let result = super::ext4::rename_at(
            old_resolved.mount.0,
            &old_resolved.inner,
            &new_resolved.inner,
            flags,
        )
        .map_err(super::map_ext4);
        if result.is_ok() {
            super::invalidate_after_path_change(&old_path);
            super::invalidate_after_path_change(&new_path);
            super::unmark_deleted(&new_path);
        }
        result
    }

    /// 删除文件或符号链接。若目标为目录，返回 `IsDirectory` 错误。
    pub fn unlink(path: &str) -> Result<(), SysError> {
        let path = super::normalize_path(path)?;
        if remove_symlink(&path).is_ok() {
            super::invalidate_after_path_change(&path);
            return Ok(());
        }
        let resolved = resolve_ext4_path(&path)?;
        match super::ext4::unlink_at(resolved.mount.0, &resolved.inner) {
            Ok(()) => {
                super::invalidate_after_path_change(&path);
                Ok(())
            }
            Err(super::ext4::FsError::InvalidPath) => Err(SysError::IsDirectory),
            Err(err) => Err(super::map_ext4(err)),
        }
    }

    /// 删除空目录。
    pub fn rmdir(path: &str) -> Result<(), SysError> {
        let path = super::normalize_path(path)?;
        let resolved = resolve_ext4_path(&path)?;
        match super::ext4::rmdir_at(resolved.mount.0, &resolved.inner) {
            Ok(()) => {
                super::invalidate_after_path_change(&path);
                Ok(())
            }
            Err(err) => Err(super::map_ext4(err)),
        }
    }

    /// 读取符号链接指向的目标路径。
    pub fn readlink(path: &str) -> Result<alloc::string::String, SysError> {
        let path = super::normalize_path(path)?;
        super::find_symlink(&path).ok_or(SysError::NotFound)
    }

    /// 返回当前工作目录路径（绝对路径）。
    pub fn current_cwd() -> alloc::string::String {
        super::task::current()
            .and_then(|task| super::task::cwd(task).ok())
            .unwrap_or_else(|| alloc::string::String::from("/"))
    }

    /// 设置当前工作目录。
    pub fn set_current_cwd(path: &str) {
        if let Some(task) = super::task::current() {
            let cwd = super::normalize_components("/", path);
            let _ = super::task::set_cwd(task, &cwd);
        }
    }

    /// 将路径转为绝对路径：若已以 `/` 开头则直接规范化，否则以当前工作目录为基准拼接。
    pub fn absolutize(path: &str) -> alloc::string::String {
        if is_absolute(path) {
            return super::normalize_components("/", path);
        }
        super::normalize_components(&current_cwd(), path)
    }

    fn mounted_root(kind: NodeKind) -> Result<Lookup, SysError> {
        if mount::is_root_mounted() {
            Ok(Lookup { kind })
        } else {
            Err(SysError::NotFound)
        }
    }
}

