pub mod posix_time {
    use super::super::need::*;

    /// 表示当前时间的结构体。
    #[repr(C)]
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct TimeSpec {
        pub tv_sec: isize,
        pub tv_nsec: isize,
    }

    impl TimeSpec {
        /// 从纳秒计数构造 `TimeSpec`。
        pub fn from_ns(ns: u64) -> Self {
            let sec = ns / 1_000_000_000;
            let nsec = ns % 1_000_000_000;
            Self {
                tv_sec: sec as isize,
                tv_nsec: nsec as isize,
            }
        }

        /// 转成毫秒计数，供旧的毫秒接口复用同一套时间拆分逻辑。
        pub fn as_msec(self) -> usize {
            (self.tv_sec as usize)
                .saturating_mul(1000)
                .saturating_add((self.tv_nsec as usize) / 1_000_000)
        }

        /// 转成 `timeval` 的两个字段：秒和微秒。
        pub fn as_timeval_fields(self) -> [isize; 2] {
            [self.tv_sec, self.tv_nsec / 1000]
        }
    }

    /// 提供 当前的毫秒计时
    /// 开机后时间
    /// 返回：`usize`。
    pub fn now_msec() -> usize {
        now().as_msec()
    }

    /// 提供当前的计时
    /// 开机后时间
    /// 返回TimeSpec
    pub fn now() -> TimeSpec {
        TimeSpec::from_ns(clock::now_ns())
    }
}

