pub mod socket {
    use alloc::vec::Vec;
    use core::cell::UnsafeCell;
    use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

    use super::super::need::*;

    /// EXTERNAL_FD_KIND 常量，属于该能力对外暴露的稳定接口。
    pub const EXTERNAL_FD_KIND: u32 = 0x534f_434b;

    /// SocketHandle 结构体，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct SocketHandle(pub usize);

    /// SocketInfo 结构体，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct SocketInfo {
        pub readable: bool,
        pub writable: bool,
        pub bound_port: Option<u16>,
        pub peer_port: Option<u16>,
    }

    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    struct Socket {
        fd: fd::Fd,
        bound_port: Option<u16>,
        peer_port: Option<u16>,
        readable: bool,
        writable: bool,
    }

    static NEXT_SOCKET: AtomicUsize = AtomicUsize::new(1);
    static SOCKETS: Store<Vec<Option<Socket>>> = Store::new(Vec::new());

    /// 创建对象。
    ///
    /// 参数：
    /// - `_domain`：`_domain` 参数，类型见函数签名。
    /// - `_ty`：`_ty` 参数，类型见函数签名。
    /// - `_protocol`：`_protocol` 参数，类型见函数签名。
    ///
    /// 返回：成功时返回 `SocketHandle`；失败时返回 `fd::SysError`。
    pub fn create(
        _domain: usize,
        _ty: usize,
        _protocol: usize,
    ) -> Result<SocketHandle, fd::SysError> {
        let id = NEXT_SOCKET.fetch_add(1, Ordering::SeqCst);
        log::info!("socket: create id={}", id);
        let fd = fd::register_external(
            fd::ExternalFile {
                kind: EXTERNAL_FD_KIND,
                id,
                readable: false,
                writable: true,
            },
            0,
        )?;
        SOCKETS.with(|sockets| {
            if sockets.len() <= id {
                sockets.resize(id + 1, None);
            }
            sockets[id] = Some(Socket {
                fd,
                bound_port: None,
                peer_port: None,
                readable: false,
                writable: true,
            });
        });
        Ok(SocketHandle(id))
    }

    /// 提供 `fd` 对应的能力接口。
    ///
    /// 参数：
    /// - `handle`：`handle` 参数，类型见函数签名。
    ///
    /// 返回：成功时返回 `fd::Fd`；失败时返回 `fd::SysError`。
    pub fn fd(handle: SocketHandle) -> Result<fd::Fd, fd::SysError> {
        with_socket(handle, |socket| Ok(socket.fd))
    }

    /// 提供 `from_fd` 对应的能力接口。
    ///
    /// 参数：
    /// - `fd`：文件描述符。
    ///
    /// 返回：成功时返回 `SocketHandle`；失败时返回 `fd::SysError`。
    pub fn from_fd(fd: fd::Fd) -> Result<SocketHandle, fd::SysError> {
        let external = fd::external(fd)?;
        if external.kind != EXTERNAL_FD_KIND {
            return Err(fd::SysError::BadFileDescriptor);
        }
        Ok(SocketHandle(external.id))
    }

    /// 提供 `info` 对应的能力接口。
    ///
    /// 参数：
    /// - `handle`：`handle` 参数，类型见函数签名。
    ///
    /// 返回：成功时返回 `SocketInfo`；失败时返回 `fd::SysError`。
    pub fn info(handle: SocketHandle) -> Result<SocketInfo, fd::SysError> {
        with_socket(handle, |socket| {
            Ok(SocketInfo {
                readable: socket.readable,
                writable: socket.writable,
                bound_port: socket.bound_port,
                peer_port: socket.peer_port,
            })
        })
    }

