    /// BootMode 枚举，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub enum BootMode {
        Tests,
        Shell,
    }

    /// MountPlan 结构体，属于该能力对外暴露的稳定接口。
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct MountPlan {
        pub root_device: &'static str,
        pub extra_device: &'static str,
        pub extra_mount: &'static str,
        pub command: &'static str,
        pub mode: BootMode,
    }

    static ROOT_MOUNTED: AtomicBool = AtomicBool::new(false);
    static EXTRA_MOUNTED: AtomicBool = AtomicBool::new(false);
    static SELECTED_MODE: AtomicUsize = AtomicUsize::new(0);

    /// 提供 `plan_for` 对应的能力接口。
    ///
    /// 参数：
    /// - `command`：`command` 参数，类型见函数签名。
    ///
    /// 返回：`MountPlan`。
    pub fn plan_for(command: &'static str) -> MountPlan {
        let mode = match option_env!("SHELL_ENABLE") {
            Some("1") => BootMode::Shell,
            _ => BootMode::Tests,
        };
        MountPlan {
            root_device: "/dev/vda",
            extra_device: "/dev/vdb",
            extra_mount: "/mnt",
            command,
            mode,
        }
    }

    /// 提供 `mount` 对应的能力接口。
    ///
    /// 参数：
    /// - `plan`：`plan` 参数，类型见函数签名。
    pub fn mount(plan: MountPlan) {
        log::info!(
            "rootfs: mount mode={:?} extra_device={} extra_mount={}",
            plan.mode,
            plan.extra_device,
            plan.extra_mount
        );
        SELECTED_MODE.store(
            match plan.mode {
                BootMode::Tests => 0,
                BootMode::Shell => 1,
            },
            Ordering::SeqCst,
        );
        if let Err(err) = mount::mount_ext4_root(0) {
            log::info!("rootfs: root ext4 mount failed: {:?}", err);
        }
        if matches!(plan.mode, BootMode::Tests) {
            if let Err(err) = mount::mount_extra_ext4(1, plan.extra_mount) {
                log::info!(
                    "rootfs: extra ext4 mount {} at {} failed: {:?}",
                    plan.extra_device,
                    plan.extra_mount,
                    err
                );
            }
        }
        ROOT_MOUNTED.store(true, Ordering::SeqCst);
        EXTRA_MOUNTED.store(mount::is_extra_mounted(), Ordering::SeqCst);
        log::info!(
            "rootfs: mounted root={} extra={}",
            ROOT_MOUNTED.load(Ordering::SeqCst),
            EXTRA_MOUNTED.load(Ordering::SeqCst)
        );
    }

    /// 判断默认根文件系统是否已经挂载。
    ///
    /// 返回：`bool`。
    pub fn is_root_mounted() -> bool {
        ROOT_MOUNTED.load(Ordering::SeqCst)
    }

    /// 判断extramounted是否成立。
    ///
    /// 返回：`bool`。
    pub fn is_extra_mounted() -> bool {
        EXTRA_MOUNTED.load(Ordering::SeqCst)
    }

        }
