    const ROOT_FREE_BLOCKS: u64 = 16 * 1024;
    const MIN_DIRENT64_RECORD: usize = 24;

    /// `read(fd, buf, len)` —— 从 fd 读取最多 len 字节到用户缓冲区。
    pub fn read(fd: usize, user_buf: usize, len: usize) -> isize {
        let mut buf = alloc::vec![0; len];
        match need::fd::read(need::fd::Fd::from_usize(fd), &mut buf) {
            Ok(read_len) => match need::syscall_args::write_buffer(user_buf, &buf[..read_len]) {
                Ok(()) => need::errno::ret(read_len),
                Err(_) => need::errno::err(need::errno::EFAULT),
            },
            Err(err) => map_sys_error(err),
        }
    }

    /// `write(fd, buf, len)` —— 将用户缓冲区中最多 len 字节写入 fd。
    pub fn write(fd: usize, user_buf: usize, len: usize) -> isize {
        let data = match need::syscall_args::read_buffer(user_buf, len) {
            Ok(data) => data,
            Err(_) => return need::errno::err(need::errno::EFAULT),
        };

        match need::fd::write(need::fd::Fd::from_usize(fd), &data) {
            Ok(written) => need::errno::ret(written),
            Err(err) => map_sys_error(err),
        }
    }

    /// `readv(fd, iov, iovcnt)` —— 从 fd 分散读取到多个用户缓冲区。
    pub fn readv(fd: usize, iov_ptr: usize, iov_count: usize) -> isize {
        const IOV_MAX: usize = 1024;
        if iov_count > IOV_MAX {
            return need::errno::err(need::errno::EINVAL);
        }

        let mut total_len = 0usize;
        let mut iovs: alloc::vec::Vec<(usize, usize)> = alloc::vec![];
        for index in 0..iov_count {
            let entry = iov_ptr + index * size_of::<usize>() * 2;
            let base = match read_usize(entry) {
                Ok(value) => value,
                Err(err) => return err,
            };
            let len = match read_usize(entry + size_of::<usize>()) {
                Ok(value) => value,
                Err(err) => return err,
            };
            total_len = total_len.saturating_add(len);
            iovs.push((base, len));
        }

        let mut buf = alloc::vec![0; total_len];
        let read_len = match need::fd::read(need::fd::Fd::from_usize(fd), &mut buf) {
            Ok(len) => len,
            Err(err) => return map_sys_error(err),
        };

        let mut offset = 0usize;
        for (base, len) in &iovs {
            if *len == 0 || offset >= read_len {
                continue;
            }
            let remain = read_len - offset;
            let chunk = core::cmp::min(*len, remain);
            match need::syscall_args::write_buffer(*base, &buf[offset..offset + chunk]) {
                Ok(()) => offset += chunk,
                Err(_) => return need::errno::err(need::errno::EFAULT),
            }
        }
        need::errno::ret(read_len)
    }

    /// `writev(fd, iov, iovcnt)` —— 从多个用户缓冲区聚集写入 fd。
    pub fn writev(fd: usize, iov_ptr: usize, iov_count: usize) -> isize {
        const IOV_MAX: usize = 1024;
        if iov_count > IOV_MAX {
            return need::errno::err(need::errno::EINVAL);
        }

        let mut total = 0usize;
        for index in 0..iov_count {
            let entry = iov_ptr + index * size_of::<usize>() * 2;
            let base = match read_usize(entry) {
                Ok(value) => value,
                Err(err) => return err,
            };
            let len = match read_usize(entry + size_of::<usize>()) {
                Ok(value) => value,
                Err(err) => return err,
            };

