/// 进程退出与回收：使当前任务退出（子进程自动过继给祖父进程），或阻塞等待任意子进程退出并收集其退出码。
pub mod exit_wait {
    use super::super::need::*;

    #[derive(Debug, Clone, PartialEq, Eq)]
    /// 子进程退出结果：封装已回收子进程的 TaskId 以及按 waitpid 语义编码的退出状态（高 8 位为退出码）。
    pub struct WaitStatus {
        pub pid: task::TaskId,
        pub raw_status: usize,
    }

    /// 以退出码 code 终止当前任务：将任务标记为 Exited，其存活子进程自动过继给父进程；若当前任务正在运行则调度器将切换上下文。
    pub fn exit_current(code: isize) -> Result<(), sys_error::SysError> {
        let task = task::current().ok_or(sys_error::SysError::NoSys)?;
        log::info!("exit_wait: exit current={:?} code={}", task, code);
        task::exit(task, code).map_err(map_task)?;
        run::schedule();
        Ok(())
    }

    /// 回收一个已退出子进程：若有僵尸子进程则立即返回其退出状态；若无已退出子进程但有存活子进程则将当前任务阻塞等待；若无任何子进程则返回 None。
    pub fn wait_current() -> Result<Option<WaitStatus>, sys_error::SysError> {
        loop {
            let task = task::current().ok_or(sys_error::SysError::NoSys)?;
            log::info!("exit_wait: wait current={:?}", task);
            if let Some(status) = try_wait_task(task)? {
                return Ok(Some(status));
            }
            if task::has_children(task).map_err(map_task)? {
                log::info!("exit_wait: block current={:?}", task);
                task::mark_blocked(task).map_err(map_task)?;
                run::schedule();
                continue;
            }
            return Ok(None);
        }
    }

    /// 非阻塞地回收一个已退出子进程；没有僵尸子进程时直接返回 None。
    pub fn try_wait_current() -> Result<Option<WaitStatus>, sys_error::SysError> {
        let task = task::current().ok_or(sys_error::SysError::NoSys)?;
        try_wait_task(task)
    }

    fn try_wait_task(task: task::TaskId) -> Result<Option<WaitStatus>, sys_error::SysError> {
        let Some(child) = task::take_exited_child(task).map_err(map_task)? else {
            return Ok(None);
        };
        log::info!(
            "exit_wait: reap child={:?} status={:?}",
            child.id,
            child.exit_code
        );
        Ok(Some(WaitStatus {
            pid: child.id,
            raw_status: ((child.exit_code.unwrap_or(0) as usize) & 0xff) << 8,
        }))
    }

    fn map_task(error: task::TaskError) -> sys_error::SysError {
        match error {
            task::TaskError::NoMemory => sys_error::SysError::TooManyOpenFiles,
            task::TaskError::BadAddress | task::TaskError::Memory(_) => sys_error::SysError::Fault,
            task::TaskError::NotFound => sys_error::SysError::NotFound,
            task::TaskError::InvalidState => sys_error::SysError::NoSys,
        }
    }
}

