pub fn init() -> crate::init::InitResult {
    let raw = need::boot_raw::raw();
    unsafe {
        BOOT_INFO = BootInfo {
            boot_cpu: raw.boot_cpu,
            payload: raw.payload,
            source: match raw.source {
                crate::arch::RawBootSource::DeviceTree => BootSource::DeviceTree,
                crate::arch::RawBootSource::FirmwareTable => BootSource::FirmwareTable,
                crate::arch::RawBootSource::Unknown => BootSource::Unknown,
            },
        };
        MEMORY_REGION_COUNT = 0;
        RESERVED_REGION_COUNT = 0;
        USABLE_REGION_COUNT = 0;
        INITRD = None;
    }

    let parsed = match raw.source {
        crate::arch::RawBootSource::DeviceTree if raw.payload != 0 => {
            parse_fdt(raw.payload).is_ok()
        }
        _ => false,
    };
    if !parsed {
        install_arch_fallback_memory();
    }

    reserve_kernel();
    normalize_usable_regions();
    Ok(())
}

