struct LazyFile {
    path: String,
    file_id: file::FileId,
    refs: usize,
}

struct LazyFileCell {
    locked: AtomicBool,
    files: UnsafeCell<Option<Vec<Option<LazyFile>>>>,
}

unsafe impl Sync for LazyFileCell {}

impl LazyFileCell {
    const fn new() -> Self {
        Self {
            locked: AtomicBool::new(false),
            files: UnsafeCell::new(None),
        }
    }

    fn with<R>(&self, f: impl FnOnce(&mut Vec<Option<LazyFile>>) -> R) -> R {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
        let result = unsafe {
            let files = &mut *self.files.get();
            if files.is_none() {
                *files = Some(Vec::new());
            }
            f(files.as_mut().unwrap())
        };
        self.locked.store(false, Ordering::Release);
        result
    }
}

/// ExecRequest 结构体，属于该能力对外暴露的稳定接口。
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExecRequest {
    pub path: String,
    pub argv: Vec<String>,
}

/// 提供 `exec` 对应的能力接口。
///
/// 参数：
/// - `path`：要访问的路径，通常要求为绝对路径且不能包含 NUL 字节。
/// - `argv`：`argv` 参数，类型见函数签名。
///
/// 返回：`SysResult<()>`。
pub fn exec(path: &str, argv: &[&str]) -> SysResult<()> {
    exec_with_env(path, argv, &[])
}

/// 提供带环境变量的 `exec` 入口。
pub fn exec_with_env(path: &str, argv: &[&str], envp: &[&str]) -> SysResult<()> {
    log::info!("exec: request path={path} argc={}", argv.len());

    // 这里会处理shebang
    let target = resolve_exec_target(path, argv)?;
    log::info!(
        "exec: target path={} argc={}",
        target.path,
        target.argv.len()
    );
    // elf 检查，如果不是elf会报ENOEXEC
    validate_executable_format(&target.path)?;
    let image = elf::load(&target.path)?;
    log::info!(
        "exec: elf loaded entry={:#x} interp={}",
        image.entry,
        image.interpreter.is_some()
    );
    let space = user_memory::new_address_space().map_err(map_memory_error)?;
    log::info!("exec: address space allocated {:?}", space);

    let result = (|| {
        log::info!("exec: map executable");
        map_object(space, &image.executable)?;
        if let Some(interpreter) = image.interpreter.as_ref() {
            log::info!("exec: map interpreter {}", interpreter.path);
            map_object(space, interpreter)?;
        }
        user_memory::set_brk(space, image.executable.brk_start).map_err(map_memory_error)?;

        log::info!("exec: map stack");
        let stack_top = user_memory::map_stack(space).map_err(map_memory_error)?;
        let user_stack = init_user_stack(
            space,
            stack_top,
            &target.path,
            &target.argv,
            envp,
            &image.auxv,
        )?;
        let tls = setup_tls(space, &image.executable)?;
        log::info!("exec: user stack ready sp={:#x}", user_stack);

        let task_id = if let Some(task) = task::current() {
            log::info!("exec: replace current task {:?}", task);
            let old = task::replace_image(task, image.entry, user_stack, tls, space, path)
                .map_err(map_task_error)?;
            user_memory::activate(space).map_err(map_memory_error)?;
            if let Some(old) = old {
                if task::address_space_ref_count(old) == 0 {
                    let _ = user_memory::destroy(old);
                }
            }
            task
        } else {
            log::info!("exec: spawn first user task");
            let task = task::spawn_user(task::SpawnUser {
                exec_path: path.to_string(),
                cwd: path::current_cwd(),
                entry: image.entry,
                user_stack,
                tls,
                address_space: space,
            })
            .map_err(map_task_error)?;
            log::info!("exec: set current task {:?}", task);
            task::set_current(task).map_err(map_task_error)?;
            task
        };

        log_exec_memory_layout(
            &target.path,
            task_id,
            space,
            image.entry,
            image.executable.brk_start,
            stack_top,
            user_stack,
            tls,
        );

        Ok(())
    })();

    if result.is_err() {
        let _ = user_memory::destroy(space);
    }
    result
}

fn validate_executable_format(path: &str) -> SysResult<()> {
    let file_id = file::open(path, OpenFlags::RDONLY)?;
    let mut header = [0u8; 4];
    let read_len = file::read_at(file_id, 0, &mut header)?;
    let _ = file::close(file_id);

    if read_len >= 4 && header == [0x7f, b'E', b'L', b'F'] {
        Ok(())
    } else {
        Err(SysError::ExecFormat)
    }
}

