    let value: usize;
    unsafe {
        asm!("csrr {}, sstatus", out(reg) value, options(nomem, nostack, preserves_flags));
    }
    value & SSTATUS_SIE != 0
}

pub fn wait_for_interrupt() {
    let enabled = irq_is_enabled();
    irq_enable();
    halt();
    if !enabled {
        irq_disable();
    }
}

pub fn console_putchar(byte: u8) {
    unsafe {
        let lsr = (UART16550_BASE + UART16550_LSR) as *const u8;
        while lsr.read_volatile() & UART16550_LSR_TXRDY == 0 {}
