pub fn init() -> crate::init::InitResult {
    log::info!("shell_init: enter");
    let command = api::boot_command::command_path();
    let plan = need::rootfs::plan_for(command);
    need::rootfs::mount(plan);
    if api::boot_command::current() == api::boot_command::BootCommand::BusyBoxShell {
        install_busybox_links();
    }
    log::info!("shell_init: rootfs plan ready");
    let start = need::user_entry::start(
        api::boot_command::executable_path(),
        api::boot_command::argv(),
    );
    log::info!("shell_init: user entry returned");

    need::log::record(format_args!(
        "shell_init: mount root={} extra={} at {} command={}",
        plan.root_device, plan.extra_device, plan.extra_mount, plan.command
    ));
    need::log::record(format_args!("shell_init: user entry start={start:?}"));
    Ok(())
}

