        fn list_dir(&mut self, path: &str) -> Result<Vec<DirEntry>, FsError> {
            let dir = self.open_dir(path)?;
            let entries = self.fs.ext4_dir_get_entries(dir.inode);
            let entries = entries
                .into_iter()
                .map(|entry| {
                    let kind = match entry.get_de_type() {
                        2 => NodeKind::Directory,
                        7 => NodeKind::Symlink,
                        1 => NodeKind::File,
                        _ => node_kind_from_inode_type(
                            self.fs.get_inode_ref(entry.inode).inode.file_type(),
                        ),
                    };
                    DirEntry {
                        inode: entry.inode as u64,
                        name: entry.get_name(),
                        kind,
                    }
                })
                .collect::<Vec<_>>();
            log::info!(
                "ext4: list_dir path={} inode={} entries={}",
                path,
                dir.inode,
                entries.len()
            );
            Ok(entries)
        }

        fn mkdir(&mut self, path: &str) -> Result<Ext4Node, FsError> {
            let inode = self.fs.ext4_dir_mk(path).map_err(|_| FsError::Io)?;
            log::info!("ext4: mkdir path={} inode={}", path, inode);
            Ok(Ext4Node {
                inode,
                kind: NodeKind::Directory,
            })
        }

        fn symlink(&mut self, target: &str, link_path: &str) -> Result<Ext4Node, FsError> {
            let (parent_path, name) = split_parent_name(link_path)?;
            let parent = self.open_dir(&parent_path)?;
            log::info!(
                "ext4: symlink link={} target={} parent_inode={}",
                link_path,
                target,
                parent.inode
            );
            self.fs
                .fuse_symlink(parent.inode as u64, name, target)
                .map_err(|err| match err.error() {
                    ext4_rs::Errno::EEXIST => FsError::AlreadyExists,
                    ext4_rs::Errno::ENOENT | ext4_rs::Errno::ENOTDIR => FsError::NotFound,
                    _ => FsError::Io,
                })?;
            self.lookup(link_path)
        }

        fn readlink(&mut self, path: &str) -> Result<String, FsError> {
            let node = self.lookup(path)?;
            if node.kind != NodeKind::Symlink {
                return Err(FsError::InvalidPath);
            }
            let metadata = self.metadata_by_inode(node.inode, NodeKind::Symlink)?;
            let mut buf = alloc::vec![0; metadata.size as usize];
            let read = self.read_at(node.inode, 0, &mut buf)?;
            buf.truncate(read);
            log::info!(
                "ext4: readlink path={} inode={} len={}",
                path,
                node.inode,
                read
            );
            String::from_utf8(buf).map_err(|_| FsError::InvalidPath)
        }

        fn unlink(&mut self, path: &str) -> Result<(), FsError> {
            let node = self.lookup(path)?;
            if node.kind == NodeKind::Directory {
                return Err(FsError::InvalidPath);
            }
            let (parent_path, name) = split_parent_name(path)?;
            let parent = self.open_dir(&parent_path)?;
            log::info!(
                "ext4: unlink path={} inode={} parent_inode={}",
                path,
                node.inode,
                parent.inode
            );
            self.fs
                .fuse_unlink(parent.inode as u64, name)
                .map(|_| ())
                .map_err(|err| match err.error() {
                    ext4_rs::Errno::ENOENT | ext4_rs::Errno::ENOTDIR => FsError::NotFound,
                    _ => FsError::Io,
                })
        }

        fn rmdir(&mut self, path: &str) -> Result<(), FsError> {
            let node = self.lookup(path)?;
            if node.kind != NodeKind::Directory {
                return Err(FsError::InvalidPath);
            }
            if self.fs.dir_has_entry(node.inode) {
                return Err(FsError::InvalidPath);
            }
            let (parent_path, name) = split_parent_name(path)?;
            let parent = self.open_dir(&parent_path)?;
            log::info!(
                "ext4: rmdir path={} inode={} parent_inode={}",
                path,
                node.inode,
                parent.inode
            );
            self.fs
                .fuse_rmdir(parent.inode as u64, name)
                .map(|_| ())
                .map_err(|err| match err.error() {
                    ext4_rs::Errno::ENOENT | ext4_rs::Errno::ENOTDIR => FsError::NotFound,
                    ext4_rs::Errno::EINVAL | ext4_rs::Errno::ENAMETOOLONG => FsError::InvalidPath,
                    _ => FsError::Io,
                })
        }

        fn rename(&mut self, old_path: &str, new_path: &str, flags: u32) -> Result<(), FsError> {
            let (old_parent_path, old_name) = split_parent_name(old_path)?;
            let (new_parent_path, new_name) = split_parent_name(new_path)?;
            let old_parent = self.open_dir(&old_parent_path)?;
            let new_parent = self.open_dir(&new_parent_path)?;
            log::info!(
                "ext4: rename old={} new={} old_parent_inode={} new_parent_inode={} flags={:#x}",
                old_path,
                new_path,
                old_parent.inode,
                new_parent.inode,
                flags
            );
            self.fs
                .fuse_rename(
                    old_parent.inode as u64,
                    old_name,
                    new_parent.inode as u64,
                    new_name,
                    flags,
                )
                .map(|_| ())
                .map_err(|err| match err.error() {
                    ext4_rs::Errno::EEXIST => FsError::AlreadyExists,
                    ext4_rs::Errno::ENOENT | ext4_rs::Errno::ENOTDIR => FsError::NotFound,
                    ext4_rs::Errno::EINVAL | ext4_rs::Errno::ENAMETOOLONG => FsError::InvalidPath,
                    _ => FsError::Io,
                })
        }

        fn read_at(&mut self, inode: u32, offset: usize, buf: &mut [u8]) -> Result<usize, FsError> {
            let data = self
                .fs
                .ext4_file_read(inode as u64, buf.len() as u32, offset as i64)
