use crate::arch::TrapFrame;
pub const MAX_CALLEE_SAVED_REGS: usize = 12;

#[repr(C)]
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq)]
pub struct ThreadContext {
    /// Kernel stack pointer. Kept at offset 0 for arch switch assembly.
    pub sp: usize,
    /// Kernel thread pointer / CPU-local pointer. Kept at offset 1.
    pub tp: usize,
    /// Callee-saved registers. RISC-V uses all 12; LoongArch64 uses the first 10.
    pub saved: [usize; MAX_CALLEE_SAVED_REGS],
    /// Return address restored by the context switcher. New kernel threads put entry here.
    pub pc: usize,
    pub arg: usize,
    pub tls: usize,
    pub page_table: usize,
    pub user_stack: usize,
    pub flags: usize,
}

impl ThreadContext {
    pub const fn empty() -> Self {
        Self {
            sp: 0,
            tp: 0,
            saved: [0; MAX_CALLEE_SAVED_REGS],
            pc: 0,
            arg: 0,
            tls: 0,
            page_table: 0,
            user_stack: 0,
            flags: 0,
        }
    }

    pub fn set_saved(&mut self, index: usize, value: usize) {
        if let Some(slot) = self.saved.get_mut(index) {
            *slot = value;
        }
    }
}

pub fn init_kernel(ctx: &mut ThreadContext, entry: usize, arg: usize, stack_top: usize) {
    *ctx = ThreadContext::empty();
    ctx.pc = entry;
    ctx.arg = arg;
    ctx.sp = stack_top;
    ctx.tp = super::cpu::current_id();
}
// 创建一个全新的用户线程上下文，准备进入用户态
pub fn init_user(
    ctx: &mut ThreadContext,
    entry: usize,
    user_stack: usize,
    kernel_stack_top: usize,
    page_table: usize,
    tls: usize,
) {
    *ctx = ThreadContext::empty();
    ctx.pc = entry;
    ctx.arg = user_stack;
    ctx.sp = kernel_stack_top;
    ctx.user_stack = user_stack;
    ctx.page_table = page_table;
    ctx.tls = tls;
    ctx.tp = super::cpu::current_id();
}

/// 创建一个 fork 子进程的线程上下文。
/// 子进程醒来时走 trap 退出路径回到用户态，a0 = 0。
pub fn init_fork(
    ctx: &mut ThreadContext,
    old_ctx: &ThreadContext,
    old_tf: TrapFrame,
    user_stack: usize,
    kernel_stack_top: usize,
    page_table: usize,
    tls: usize,
) {
    *ctx = *old_ctx;
    let tf_addr = kernel_stack_top - 304;
    let mut tf = old_tf;
    super::platform::fork_child_trapframe(&mut tf);
    unsafe {
        *(tf_addr as *mut TrapFrame) = tf;
    }
    ctx.pc = super::platform::fork_return_entry();
    ctx.sp = tf_addr;
    // fork 子任务第一次返回用户态前，先用这个寄存器把页表令牌带给架构入口。
    ctx.set_saved(0, page_table);
    ctx.user_stack = user_stack;
    ctx.page_table = page_table;
    ctx.tls = tls;
    ctx.arg = user_stack;
    ctx.tp = super::cpu::current_id();
}

pub fn set_tls(ctx: &mut ThreadContext, tls: usize) {
    ctx.tls = tls;
}

pub fn set_current_kernel_stack(stack_top: usize) {
    super::platform::set_current_kernel_stack(stack_top);
}

pub fn enter_user(
    entry: usize,
    user_stack: usize,
    kernel_stack_top: usize,
    page_table: usize,
    tls: usize,
) -> ! {
    super::platform::enter_user(entry, user_stack, kernel_stack_top, page_table, tls)
}

pub unsafe fn switch(prev: *mut ThreadContext, next: *const ThreadContext) {
    unsafe {
        super::platform::context_switch(prev, next);
    }
}

