fn mount_root_impl(slot: usize, device_index: usize) -> Result<(), MountError> {
    let id = need::block::by_index(device_index).ok_or(MountError::Device)?;

    let device = KernelBlockDevice::new(id);
    if !device.has_ext4_magic() {
        return Err(MountError::Format);
    }

    let block = Arc::new(device);
    let root = ext4_rs::Ext4::open(block);
    ROOTS.with(|roots| {
        while roots.len() <= slot {
            roots.push(None);
        }
        roots[slot] = Some(Ext4Root { fs: root });
    });
    ROOT_MOUNT_MASK.fetch_or(
        1usize << slot.min(usize::BITS as usize - 1),
        Ordering::SeqCst,
    );
    log::info!(
        "ext4: mounted root slot={} device_index={}",
        slot,
        device_index
    );
    Ok(())
}

fn mount_first_root_impl() -> Result<(), MountError> {
    mount_root_impl(0, 0)
}

fn with_root<R>(
    slot: usize,
    f: impl FnOnce(&mut Ext4Root) -> Result<R, FsError>,
) -> Result<R, FsError> {
    ROOTS.with(|roots| {
        let root = roots
            .get_mut(slot)
            .and_then(Option::as_mut)
            .ok_or(FsError::NotMounted)?;
        f(root)
    })
}

