unsafe impl Sync for SpacesCell {}

impl SpacesCell {
    const fn new() -> Self {
        Self(UnsafeCell::new(None))
    }

    unsafe fn with<R>(&self, f: impl FnOnce(&mut Vec<Option<Space>>) -> R) -> R {
        let spaces = unsafe { &mut *self.0.get() };
        if spaces.is_none() {
            *spaces = Some(Vec::new());
            spaces.as_mut().unwrap().push(None);
        }
        f(spaces.as_mut().unwrap())
    }
}

pub(super) fn new_address_space() -> Result<AddressSpace, MemoryError> {
    with_spaces(|spaces| {
        let table = map::new_table().map_err(map_page_error)?;
        map_kernel_identity(table)?;
        let space = Space {
            table,
            mappings: Vec::new(),
            brk: 0,
        };

        if let Some((index, slot)) = spaces
            .iter_mut()
            .enumerate()
            .skip(1)
            .find(|(_, slot)| slot.is_none())
        {
            *slot = Some(space);
            log::info!("user_memory: new space {:?}", AddressSpace(index));
            return Ok(AddressSpace(index));
        }

        spaces.push(Some(space));
        let id = AddressSpace(spaces.len() - 1);
        log::info!("user_memory: new space {:?}", id);
        Ok(id)
    })
}

pub(super) fn clone_address_space(source: AddressSpace) -> Result<AddressSpace, MemoryError> {
    let snapshot = with_space(source, |space| {
        space
            .mappings
            .iter()
            .map(|mapping| {
                (
                    mapping.start,
                    mapping.len,
                    mapping.perm,
                    mapping.pages.clone(),
                    mapping.source,
                )
            })
            .collect::<Vec<_>>()
    })?;
    let source_brk = brk(source)?;
    let cloned = new_address_space()?;
    let result = (|| {
        for (start, len, perm, pages, source) in snapshot {
            clone_mapping(cloned, start, len, perm, pages, source)?;
        }
        with_space(cloned, |space| {
            space.brk = source_brk;
        })?;
        Ok(())
    })();
    if result.is_err() {
        let _ = destroy(cloned);
    }
    result.map(|()| cloned)
}

