/// 提供 `load` 对应的能力接口。
///
/// 参数：
/// - `path`：要访问的路径，通常要求为绝对路径且不能包含 NUL 字节。
///
/// 返回：`SysResult<ElfImage>`。
pub fn load(path: &str) -> SysResult<ElfImage> {
    log::info!("elf: load executable {path}");
    let executable = load_object(path, 0)?;
    let mut entry = executable.info.entry;
    let mut auxv = build_auxv(&executable.info);
    let mut interpreter = None;

    if let Some(loader_path) = executable.info.interpreter.as_deref() {
        let resolved = resolve_interpreter_path(loader_path, path)?;
        log::info!("elf: load interpreter {resolved}");
        let object = load_object(&resolved, INTERP_BIAS)?;
        entry = object
            .info
            .entry
            .checked_add(INTERP_BIAS)
            .ok_or(SysError::InvalidArgument)?;
        auxv_set(&mut auxv, AT_ENTRY, executable.info.entry);
        auxv_set(&mut auxv, AT_BASE, INTERP_BIAS);
        interpreter = Some(object);
    }

    Ok(ElfImage {
        executable,
        interpreter,
        entry,
        auxv,
    })
}

fn load_object(path: &str, load_bias: usize) -> SysResult<ElfObject> {
    log::info!("elf: read object {path} bias={:#x}", load_bias);
    let prefix = read_prefix(path)?;
    log::info!("elf: prefix read {} bytes from {path}", prefix.len());
    let info = parse_info(&prefix)?;
    let segments = load_segments(&prefix, load_bias)?;
    log::info!("elf: parsed {} load segments from {path}", segments.len());
    let tls = tls_template(&prefix)?;
    let brk_start = brk_start(&segments)?;

    Ok(ElfObject {
        path: String::from(path),
        prefix,
        info,
        segments,
        tls,
        load_bias,
        brk_start,
    })
}

fn read_prefix(path: &str) -> SysResult<Vec<u8>> {
    log::info!("elf: open {path}");
    let file_id = file::open(path, OpenFlags::RDONLY)?;
    log::info!("elf: opened {path} as {:?}", file_id);
    let result = read_prefix_from_file(file_id);
    let _ = file::close(file_id);
    result
}

fn read_prefix_from_file(file_id: file::FileId) -> SysResult<Vec<u8>> {
    let total = core::cmp::min(file::metadata(file_id)?.size as usize, MAX_PREFIX_READ);
    let mut prefix = Vec::new();

    read_prefix_to(file_id, &mut prefix, total, PAGE_SIZE)?;

    let ph_end = program_headers_end(&prefix)?;
    read_prefix_to(file_id, &mut prefix, total, ph_end)?;

    if let Some(interp_end) = interp_end(&prefix)? {
        read_prefix_to(file_id, &mut prefix, total, interp_end)?;
    }

    Ok(prefix)
}

