/// 先唤醒所有已到期的 Blocked 任务，再选出第一个非当前任务的 Ready 任务，将其切换到 Running 并返回其 ID。
pub fn next_ready() -> Option<TaskId> {
    SCHEDULER.with(|scheduler| {
        let now = need::clock::now_ns();
        for task in scheduler.tasks.iter_mut() {
            if let State::Blocked {
                deadline_ns: Some(deadline),
            } = task.state
            {
                if deadline <= now {
                    task.state = State::Ready;
                }
            }
        }

        let current = CURRENT.load(Ordering::SeqCst);
        let next = scheduler
            .tasks
            .iter_mut()
            .find(|task| {
                task.id != TaskId(0)
                    && task.id != TaskId(current)
                    && matches!(task.state, State::Ready)
            })
            .map(|task| {
                task.state = State::Running;
                task.id
            });

        if let Some(id) = next {
            CURRENT.store(id.0, Ordering::SeqCst);
        }
        next
    })
}
/// 实际调度发生的函数。
pub fn schedule() {
    let _irq_off = need::irq::IrqOff::new();
    // 续订定时器，不管是否真的发生切换
    need::alarm::clear_interrupt();
    need::alarm::set_periodic(100);

    // 一次持锁完成：唤醒到期 → 挑下一个 → 取裸指针
    let swap = SCHEDULER.with(|scheduler| {
        let now = need::clock::now_ns();
        for task in scheduler.tasks.iter_mut() {
            if let State::Blocked {
                deadline_ns: Some(deadline),
            } = task.state
            {
                if deadline <= now {
                    task.state = State::Ready;
                }
            }
        }

        let current = TaskId(CURRENT.load(Ordering::SeqCst));
        let cur_idx = scheduler.tasks.iter().position(|t| t.id == current);
        // 用下标避免同时持有 mut 和共享引用
        let Some(next_idx) = scheduler.tasks.iter().position(|task| {
            task.id != TaskId(0) && task.id != current && matches!(task.state, State::Ready)
        }) else {
            if cur_idx.is_none_or(|idx| !matches!(scheduler.tasks[idx].state, State::Running)) {
                CURRENT.store(0, Ordering::SeqCst);
            }
            return None;
        };

        let cur_idx = cur_idx?;
        if matches!(scheduler.tasks[cur_idx].state, State::Running) {
            scheduler.tasks[cur_idx].state = State::Ready;
        }
        scheduler.tasks[next_idx].state = State::Running;
        CURRENT.store(scheduler.tasks[next_idx].id.0, Ordering::SeqCst);

        let cur_ptr: *const ThreadContext = &scheduler.tasks[cur_idx].context;
        let next_ptr: *const ThreadContext = &scheduler.tasks[next_idx].context;
        Some((cur_ptr, next_ptr))
    });

    if let Some((prev, next)) = swap {
        unsafe { need::thread_context::switch(prev, next) };
    }
}

