/// Futex（快速用户空间互斥）：基于用户虚拟地址实现内核级等待/唤醒/重排队，为 libc 互斥库提供底层同步原语。等待者可设置绝对超时（纳秒），唤醒操作从等待队列移除并向调度器提交就绪标记。
pub mod futex {
    use alloc::vec::Vec;
    use core::cell::UnsafeCell;
    use core::sync::atomic::{AtomicBool, Ordering};

    use super::super::need::*;

    static WAITERS: Store<Vec<Waiter>> = Store::new(Vec::new());

    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    struct Waiter {
        uaddr: usize,
        task: task::TaskId,
    }

    /// 原子性地检查 *uaddr == expected，若相等则将当前任务加入该地址的等待队列并阻塞；若不相等则立即返回 WouldBlock。deadline_ns 为可选绝对超时时间，已到期则直接返回 TimedOut。
    pub fn wait_until(
        uaddr: usize,
        expected: u32,
        deadline_ns: Option<u64>,
    ) -> Result<(), sys_error::SysError> {
        if deadline_ns.is_some_and(|deadline| deadline <= clock::now_ns()) {
            return Err(sys_error::SysError::TimedOut);
        }
        let current = task::current().ok_or(sys_error::SysError::NoSys)?;
        let actual = read_u32(uaddr)?;
        if actual != expected {
            log::info!(
                "futex: wait would_block uaddr={:#x} expected={} actual={}",
                uaddr,
                expected,
                actual
            );
            return Err(sys_error::SysError::WouldBlock);
        }
        log::info!(
            "futex: wait task={:?} uaddr={:#x} deadline={:?}",
            current,
            uaddr,
            deadline_ns
        );
        WAITERS.with(|waiters| {
            if !waiters
                .iter()
                .any(|waiter| waiter.uaddr == uaddr && waiter.task == current)
            {
                waiters.push(Waiter {
                    uaddr,
                    task: current,
                });
            }
        });
        task::mark_blocked_until(current, deadline_ns).map_err(map_task)?;
        Ok(())
    }

    /// 唤醒在 uaddr 上等待的任务，最多唤醒 count 个——从等待队列中移除对应条目并标记任务为 Ready 状态，返回成功唤醒的任务数量。
    pub fn wake(uaddr: usize, count: usize) -> Result<usize, sys_error::SysError> {
        let mut ready = Vec::new();
        WAITERS.with(|waiters| {
            let mut index = 0;
            while index < waiters.len() && ready.len() < count {
                if waiters[index].uaddr == uaddr {
                    ready.push(waiters.remove(index).task);
                } else {
                    index += 1;
                }
            }
        });
        for task in ready.iter().copied() {
            let _ = task::mark_ready(task);
        }
        log::info!(
            "futex: wake uaddr={:#x} requested={} ready={}",
            uaddr,
            count,
            ready.len()
        );
        Ok(ready.len())
    }

    /// 原子地将等待者从 from 地址重排队到 to 地址：先从 from 唤醒 wake_count 个，再将剩余等待者中至多 requeue_count 个迁移到 to 地址上等待，返回唤醒+迁移的总任务数。
    pub fn requeue(
        from: usize,
        to: usize,
        wake_count: usize,
        requeue_count: usize,
    ) -> Result<usize, sys_error::SysError> {
        let woken = wake(from, wake_count)?;
        let mut moved = 0;
        WAITERS.with(|waiters| {
            for waiter in waiters.iter_mut().filter(|waiter| waiter.uaddr == from) {
                if moved >= requeue_count {
                    break;
                }
                waiter.uaddr = to;
                moved += 1;
            }
        });

